#include<bits/stdc++.h>
using namespace std;
int a[100010];
vector<int> v;
int main()
{
    int n=0;
    while(scanf("%d",&a[++n])==1);
    n--;
    for(int i=1;i<=n;i++)
    {
        int pos=upper_bound(v.begin(),v.end(),a[i],greater<int>())-v.begin();
        if(pos==v.size())
        {
            v.push_back(a[i]);
        }
        else
        {
            v[pos]=a[i];
        }
    }
    printf("%d\n",v.size());
    multiset<int> s;
    for(int i=1;i<=n;i++)
    {
        auto tmp=s.lower_bound(a[i]);
        if(tmp==s.end())
        {
            s.insert(a[i]);
            continue;
        }
        s.erase(tmp);
        s.insert(a[i]);
    }
    printf("%d",s.size());
    return 0;
}
